sys_script.script:
(function executeRule(current, previous) {

    var user = current.x_ctans_incentnow_sales_user;
    var plan = current.x_ctans_incentnow_plan;

    // -----------------------------------------
    // 1. Check if plan uses Quota Attainment
    // -----------------------------------------
    var ruleGR = new GlideRecord('x_ctans_incentnow_lookup_rule');
    ruleGR.addQuery('plan', plan);
    ruleGR.addQuery('active', true);
    ruleGR.addQuery('rule_type', 'quota_attainment'); // confirm value
    ruleGR.setLimit(1);
    ruleGR.query();

    if (!ruleGR.hasNext()) {
        return; //  No quota requirement
    }

    // -----------------------------------------
    // 2. Get Fiscal Year from Plan
    // -----------------------------------------
    var planGR = new GlideRecord('x_ctans_incentnow_plan');
    if (!planGR.get(plan)) {
        return;
    }

    var fiscalYear = planGR.fiscal_year; 

    // -----------------------------------------
    // 3. Check if user has active quota
    // -----------------------------------------
    var quotaGR = new GlideRecord('x_ctans_incentnow_user_quota_assignment');
    quotaGR.addQuery('user', user);
    quotaGR.addQuery('quota.fiscal_year', fiscalYear);
    quotaGR.addQuery('quota.status', 'active');
    quotaGR.setLimit(1);
    quotaGR.query();

    if (!quotaGR.hasNext()) {

        gs.addErrorMessage(
            'Cannot assign user to plan: Active quota is required for this fiscal year because the plan uses Quota Attainment rule.'
        );

        current.setAbortAction(true);
        return;
    }

})(current, previous);
